// ═══════════════════════════════════════════════════════════════════
// SEARCH FUNCTION
// ═══════════════════════════════════════════════════════════════════
function search(lat, lon, radiusMiles = 25) {
  return locations
    .map(loc => {
      const dist = haversine(lat, lon, loc.lat, loc.lon);
      return { ...loc, distanceMiles: Math.round(dist * 10) / 10 };
    })
    .filter(loc => loc.distanceMiles <= radiusMiles)
    .sort((a, b) => a.distanceMiles - b.distanceMiles);
}

module.exports = { search, locations };
